=// 1. 获取文稿与元数据
const transcript = {{ $('Set: Final Transcript for AI').item.json.video_transcript }};
const title = {{ $json.video_title || "未命名视频" }};
const author = {{ $json.video_author || "未知作者" }};

// 2. 语言设置
const languageCode = {{ $('Webhook').item.json.body.metadata.language || 'zh' }};
const langMap = { 'zh': '简体中文', 'en': 'English', 'ja': '日本語' };
const targetLang = langMap[languageCode] || '简体中文';

// 3. 构建“自适应全量归档” Prompt
let userPrompt = `
【任务】：请对以下视频文稿（解释语言：${targetLang}）进行**深度重构与归档**。

【元数据】：
- 标题：${title}
- 作者：${author}

【文稿内容】：
---
${transcript}
---

【笔记构建指令 (Note 字段)】：

**请放弃所有预设模板，根据视频内容的实际逻辑，为我生成一份结构最合理的笔记。**

**1. 🦅 全局概览 (必须包含)**
- 在笔记开头，使用 \`> [!summary] 核心摘要\` 概括全篇主旨、关键结论和适用人群。（这一部分要纯文本，不要使用任何特殊格式。）

**2. 🧱 正文构建 (由你决定结构)**
- **自拟标题**：根据内容逻辑划分 H2/H3 标题（不要加 Emoji）。
- **全量细节保留 (关键)**：
  - 我需要视频中的**所有干货**，不要过度删减。
  - **处理策略**：将核心观点列在外面，将**具体的例子、冗长的论证、次要的背景**放入折叠块 \`> [!example]- ...\` 中。让笔记看起来很短，但点开很深。
- **视觉化处理**：
  - 遇到**对比**（如 A vs B），**必须**转为 Markdown 表格。
  - 遇到**步骤**，使用有序列表。
  - 遇到**术语定义**，使用表格或粗体强调。

**3. 🧬 专项内容自动识别 (如有则必须处理)**
- **[若包含外语教学]**：自动生成一张详尽的词汇/表达表格（词汇|音标|释义|例句）。日语需标注假名/读音。
- **[若包含实操建议]**：自动在文末生成 Checklist \`- [ ]\`。
- **[若包含代码/技术]**：代码块必须指定语言。

**4. 📎 附录**
- 提及的资源链接、书籍或经典引用。

**⚠️ 质量红线**：
- **准确性**：不要编造，拿不准的保留原文。
- **JSON格式**：严禁 Markdown 标记包裹 JSON，确保 \`\\n\` 和 \`\\"\` 正确转义。
`;

// 4. 错误处理与重试逻辑 (保持不变)
const aiRetryCount = {{ $json.ai_retry_count || 0 }};
const parsingErrorDetails = {{ $json.parsing_error_details || "" }};
if (aiRetryCount > 0 && parsingErrorDetails) {
  userPrompt += `\n\n🚨 [JSON FIX MODE] Previous error: "${parsingErrorDetails}". \nPlease output STRICT VALID JSON only. Escape all quotes (\\") and newlines (\\n).`; 
}

return userPrompt;

