set +e
rm -f ${shellQuote(outputBase)}*.srt ${shellQuote(outputBase)}*.vtt ${shellQuote(outputBase)}*.json3 ${shellQuote(metaPath)} ${shellQuote(logPath)}
yt-dlp --no-check-certificate ${ytdlpArguments} --skip-download --dump-single-json --no-playlist ${shellQuote(link)} > ${shellQuote(metaPath)} 2> ${shellQuote(logPath)}
langs=$(node -e ${shellQuote(languageSelector)} ${shellQuote(metaPath)} 2>> ${shellQuote(logPath)})
if [ -z "$langs" ]; then
  printf "__NATIVE_SUBTITLE_UNCERTAIN_ORIGINAL_LANGUAGE__=1\\n"
