fi
printf "__NATIVE_SUBTITLE_LANGS__=%s\\n" "$langs"
yt-dlp --no-check-certificate ${ytdlpArguments} --skip-download --write-subs --write-auto-subs --sub-langs "$langs" --sub-format "srt/vtt/best" --convert-subs srt --no-playlist --output ${shellQuote(outputTemplate)} ${shellQuote(link)} >> ${shellQuote(logPath)} 2>&1
file=$(find /home/node/files -maxdepth 1 -type f \\( -name '${stem}*.srt' -o -name '${stem}*.vtt' \\) -print | head -n 1)
if [ -n "$file" ]; then
