  let platform = "unknown";
  let audioFilePath = "";
  let ytdlpCommand = "";
  let nativeSubtitleCommand = "";

  if (!videoLink) {
    item.json.error = "Video link is missing.";
    newItems.push(item);
    continue;
  }

  platform = detectPlatform(videoLink);

  const videoId = `${Date.now()}${Math.random().toString(36).slice(2, 15)}`;
  const audioStem = `audio_${videoId}`;
  const subtitleStem = `subtitle_${videoId}`;
  const audioOutputTemplate = `/home/node/files/${audioStem}.%(ext)s`;
  const finalAudioPath = `/home/node/files/${audioStem}.mp3`;
  const ytdlpArguments = ytdlpArgs(platform);

  if (platform !== "unknown") {
    ytdlpCommand = `yt-dlp \
  --no-check-certificate \
  ${ytdlpArguments} \
  -x --audio-format "mp3" --audio-quality 64K \
