  --output ${shellQuote(audioOutputTemplate)} \
  ${shellQuote(videoLink)}`;
    nativeSubtitleCommand = buildSubtitleCommand(platform, videoLink, subtitleStem, ytdlpArguments);
    audioFilePath = finalAudioPath;
  } else {
    item.json.error = `Unsupported video platform for link: ${videoLink}`;
  }

  item.json.platform = platform;
  item.json.ytdlp_command = ytdlpCommand.trim();
  item.json.native_subtitle_command = nativeSubtitleCommand.trim();
