const items = $input.all();
const parts =[
  { "text": "Please transcribe all text from this image/document verbatim. Do not add any commentary." }
];

for (let i = 0; i < items.length; i++) {
  const item = items[i];

  if (item.binary && item.binary.data) {
    // 【关键修复】：调用 n8n 的内置方法，从底层真实提取二进制 Buffer
    const buffer = await this.helpers.getBinaryDataBuffer(i, 'data');

    // 将 Buffer 转换为 Gemini 需要的 Base64 格式
    const base64Data = buffer.toString('base64');

    parts.push({
      "inline_data": {
        "mime_type": item.binary.data.mimeType,
        "data": base64Data
      }
    });
  }
}

return[{
   json: {
     gemini_parts: parts
   }
}];

const items = $input.all();

function cleanSubtitle(raw) {
  const seen = new Set();
  const lines = String(raw || "")
    .replace(/\r/g, "")
    .split("\n")
    .map((line) => line.trim())
    .filter((line) => line)
    .filter((line) => !line.startsWith("__NATIVE_SUBTITLE_"))
    .filter((line) => line !== "WEBVTT")
    .filter((line) => !/^\d+$/.test(line))
    .filter((line) => !/^\d{1,2}:\d{2}:\d{2}[,.]\d{3}\s+-->\s+\d{1,2}:\d{2}:\d{2}[,.]\d{3}/.test(line))
    .filter((line) => !/^NOTE($|\s)/.test(line))
    .map((line) => line.replace(/<[^>]+>/g, "").replace(/\s+/g, " ").trim())
    .filter((line) => line && !/^(align|position|line):/i.test(line));

  const deduped = [];
  for (const line of lines) {
    const key = line.toLowerCase();
    if (seen.has(key)) continue;
    seen.add(key);
    deduped.push(line);
  }
  return deduped.join("\n");
}

for (const item of items) {
  const base = $("Code: Detect Platform & Prepare Download").item.json;
  const stdout = item.json.stdout || "";
  const fileMatch = stdout.match(/^__NATIVE_SUBTITLE_FILE__=(.+)$/m);
  const languageMatch = stdout.match(/^__NATIVE_SUBTITLE_LANGS__=(.+)$/m);
  const transcript = fileMatch ? cleanSubtitle(stdout) : "";

  item.json = {
    ...base,
    ...item.json,
    native_subtitle_file: fileMatch ? fileMatch[1].trim() : "",
    native_subtitle_langs: languageMatch ? languageMatch[1].trim() : "",
    transcript_source: transcript.length >= 80 ? "native_subtitle" : "asr_fallback",
    video_transcript: transcript.length >= 80 ? transcript : "",
  };
}

return items;
